const base = env.get('SONARR_URL');
const key = env.get('SONARR_API_KEY');
if (!key) { node.error('SONARR_API_KEY not set'); return null; }
const { series_id } = msg.payload || {};
msg.url = series_id != null ? `${base}/api/v3/series/${series_id}` : `${base}/api/v3/series`;
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = { error: `HTTP ${msg.statusCode}` }; return msg; }
const arr = Array.isArray(msg.payload) ? msg.payload : [msg.payload];
msg.payload = JSON.stringify(arr.map(s => ({
  id: s.id,
  title: s.title,
  year: s.year,
  status: s.status,
  monitored: s.monitored,
  network: s.network,
  seasonCount: s.seasons ? s.seasons.filter(x => x.seasonNumber > 0).length : null,
  episodeCount: s.episodeCount,
  episodeFileCount: s.episodeFileCount,
  tvdbId: s.tvdbId,
  path: s.path
})));
return msg;

const base = env.get('SONARR_URL');
const key = env.get('SONARR_API_KEY');
if (!key) { node.error('SONARR_API_KEY not set'); return null; }
const { term } = msg.payload;
msg.url = `${base}/api/v3/series/lookup?term=${encodeURIComponent(term)}`;
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = { error: `HTTP ${msg.statusCode}` }; return msg; }
const results = (Array.isArray(msg.payload) ? msg.payload : []).slice(0, 10);
msg.payload = JSON.stringify(results.map(s => ({
  tvdbId: s.tvdbId,
  title: s.title,
  year: s.year,
  status: s.status,
  network: s.network,
  seasonCount: s.seasons ? s.seasons.filter(x => x.seasonNumber > 0).length : null,
  overview: s.overview ? s.overview.slice(0, 300) : null,
  remotePoster: s.remotePoster || null
})));
return msg;

const base = env.get('SONARR_URL');
const key = env.get('SONARR_API_KEY');
if (!key) { node.error('SONARR_API_KEY not set'); return null; }
const { tvdb_id, quality_profile_id, root_folder_path, search_on_add } = msg.payload;

const fetchJson = (path) => new Promise((resolve, reject) => {
  const u = new URL(`${base}${path}`);
  const req = http.request({
    hostname: u.hostname,
    port: parseInt(u.port) || 80,
    path: u.pathname + u.search,
    method: 'GET',
    headers: { 'X-Api-Key': key }
  }, res => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { reject(e); } });
  });
  req.on('error', reject);
  req.setTimeout(5000, () => { req.destroy(); reject(new Error('timeout')); });
  req.end();
});

const [lookup, rootFolders, qualityProfiles] = await Promise.all([
  fetchJson(`/api/v3/series/lookup?term=tvdb:${tvdb_id}`),
  fetchJson('/api/v3/rootfolder'),
  fetchJson('/api/v3/qualityprofile')
]);

const seriesTemplate = Array.isArray(lookup) ? lookup[0] : null;
if (!seriesTemplate) { node.error('Series not found for TVDB ID: ' + tvdb_id); return null; }

const qpId = quality_profile_id || (qualityProfiles[0] ? qualityProfiles[0].id : null);
const rfPath = root_folder_path || (rootFolders[0] ? rootFolders[0].path : null);
if (!qpId || !rfPath) { node.error('No quality profile or root folder configured in Sonarr'); return null; }

seriesTemplate.qualityProfileId = qpId;
seriesTemplate.rootFolderPath = rfPath;
seriesTemplate.monitored = true;
seriesTemplate.addOptions = { searchForMissingEpisodes: search_on_add !== false };

msg.url = `${base}/api/v3/series`;
msg.headers = { 'X-Api-Key': key, 'Content-Type': 'application/json' };
msg.payload = JSON.stringify(seriesTemplate);
return msg;

if (msg.statusCode >= 400) { msg.payload = { error: `HTTP ${msg.statusCode}`, detail: typeof msg.payload === 'object' ? msg.payload : {} }; return msg; }
const s = msg.payload;
msg.payload = JSON.stringify({ success: true, id: s.id, title: s.title, year: s.year, tvdbId: s.tvdbId, path: s.path, qualityProfileId: s.qualityProfileId });
return msg;

const base = env.get('SONARR_URL');
const key = env.get('SONARR_API_KEY');
if (!key) { node.error('SONARR_API_KEY not set'); return null; }
const { start_date, end_date, unmonitored } = msg.payload || {};
const start = start_date || new Date().toISOString().split('T')[0];
const end = end_date || new Date(Date.now() + 7 * 86400000).toISOString().split('T')[0];
const params = new URLSearchParams({ start, end, includeSeries: 'true', includeEpisodeFile: 'true' });
if (unmonitored) params.set('unmonitored', 'true');
msg.url = `${base}/api/v3/calendar?${params}`;
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = { error: `HTTP ${msg.statusCode}` }; return msg; }
msg.payload = JSON.stringify((Array.isArray(msg.payload) ? msg.payload : []).map(ep => ({
  seriesTitle: ep.series ? ep.series.title : null,
  episodeTitle: ep.title,
  seasonNumber: ep.seasonNumber,
  episodeNumber: ep.episodeNumber,
  airDateUtc: ep.airDateUtc,
  hasFile: ep.hasFile,
  monitored: ep.monitored
})));
return msg;

const base = env.get('SONARR_URL');
const key = env.get('SONARR_API_KEY');
if (!key) { node.error('SONARR_API_KEY not set'); return null; }
const params = new URLSearchParams({ pageSize: '50', includeSeries: 'true', includeEpisode: 'true' });
msg.url = `${base}/api/v3/queue?${params}`;
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = { error: `HTTP ${msg.statusCode}` }; return msg; }
const records = msg.payload.records || [];
msg.payload = JSON.stringify(records.map(r => ({
  id: r.id,
  seriesTitle: r.series ? r.series.title : null,
  episodeTitle: r.episode ? r.episode.title : null,
  seasonNumber: r.episode ? r.episode.seasonNumber : null,
  episodeNumber: r.episode ? r.episode.episodeNumber : null,
  quality: r.quality ? r.quality.quality.name : null,
  status: r.status,
  trackedDownloadState: r.trackedDownloadState,
  timeleft: r.timeleft || null,
  size: r.size,
  sizeleft: r.sizeleft
})));
return msg;
